import{_ as o,o as t,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"47. Long Service Leave","description":"","frontmatter":{"title":"47. Long Service Leave","eba":"Mental Health Services 2024-2028","topics":["leave","long-service-leave","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/leave/47-long-service-leave.md","filePath":"ebas/mental-health/common-terms/leave/47-long-service-leave.md"}'),a={name:"ebas/mental-health/common-terms/leave/47-long-service-leave.md"};function s(i,e,l,p,c,h){return t(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_47-long-service-leave" tabindex="-1">47. Long Service Leave <a class="header-anchor" href="#_47-long-service-leave" aria-label="Permalink to &quot;47. Long Service Leave&quot;">​</a></h1><p>Part 1 - General</p><p><strong>47.1</strong> Scope This clause is split into 4 parts:</p><p><strong>(a)</strong> Part 1 (Clauses 47.1 - 47.2) explains the scope of this clause and includes defined terms used across each Part.</p><p><strong>(b)</strong> Part 2 (Clauses 47.3 - 47.10 ) sets out the long service leave entitlement of Employees employed as a Group A Employee or Group B Employee (as defined below) at the time they take a period of long service leave or their employment ceases.</p><p><strong>(c)</strong> Part 3 (Clauses 47.11 - 47.18) sets out the long service leave entitlement of Employees employed as a Group C Employee (as defined below) at the time they take a period of long service leave or their employment ceases:</p><p><strong>(d)</strong> Part 4 (Clauses 47.19 - 47.23) contains a series of common provisions that apply in respect of all Employees.</p><p><strong>47.2</strong> Definitions The following meanings shall apply to the terms referred to below for the purposes of this clause unless a contrary intention is apparent:</p><p><strong>(a)</strong> Allowable period of absence means five weeks in addition to the total period of paid annual, long service or personal leave which the Employee actually receives on termination or for which the Employee is paid in lieu.</p><p><strong>(b)</strong> Group A Employee means, for the purpose of this clause 47:</p><p><strong>(i)</strong> a Registered Psychiatric Nurse (including a Psychiatric Clinical Educator as described in <a href="/eba/ebas/mental-health/schedules/03-role-statement-mental-health-clinical-educator.html">Schedule 3</a>)</p><p><strong>(ii)</strong> a Psychiatric Enrolled Nurse</p><p><strong>(iii)</strong> a Mental Health Officer; or</p><p><strong>(iv)</strong> Clerical Worker; or</p><p><strong>(v)</strong> a Support Services employees employed under <a href="/eba/ebas/mental-health/schedules/06-support-services-employee-classifications.html">Schedule 6</a> in the following roles (howsoever described): <strong>(A)</strong> Cleaner <strong>(B)</strong> Cook Employed Alone <strong>(C)</strong> Diet Cook <strong>(D)</strong> Food and Domestic Services Assistant</p><p><strong>(E)</strong> Food Services Supervisor <strong>(F)</strong> Gardener <strong>(G)</strong> General Services Supervisor <strong>(H)</strong> Handyperson (Unqualified) <strong>(I)</strong> Handyperson Advanced <strong>(J)</strong> Housekeeper <strong>(K)</strong> Other Cook (Unqualified/Qualified) <strong>(L)</strong> Patient Services Assistant; or <strong>(M)</strong> Trade Cook.</p><p><strong>(c)</strong> Group B Employee means, for the purpose of this clause 47:</p><p><strong>(i)</strong> Management and Administrative Officer Employees employed in a classification listed in <a href="/eba/ebas/mental-health/schedules/07-management-and-administrative-officers-classifications.html">Schedule 7</a> (Part 1, Grades 1-10 and Part 2, Grades 2-7);</p><p><strong>(ii)</strong> Support Services Employees employed under <a href="/eba/ebas/mental-health/schedules/06-support-services-employee-classifications.html">Schedule 6</a> (Levels 1- 11) in the following roles (howsoever described): <strong>(A)</strong> All other Employees <strong>(B)</strong> Courier <strong>(C)</strong> Dietary Supervisor <strong>(D)</strong> Food Monitor <strong>(E)</strong> Hospital Attendant; or <strong>(F)</strong> Security Officer; or</p><p><strong>(iii)</strong> Health Professionals (including LLEWs) employed in a role described under <a href="/eba/ebas/mental-health/schedules/05-classification-definitions-applying-to-health-professionals.html">Schedule 5</a> other than casual employees</p><p><strong>(d)</strong> Group C Employee means, for the purpose of this clause 47, an Employee employed in a classification listed in <a href="/eba/ebas/mental-health/schedules/05-classification-definitions-applying-to-health-professionals.html">Schedule 5</a> on a casual basis.</p><p><strong>(e)</strong> Institution means any Employer, or a hospital or benevolent home, community health centre, Society or Association:</p><p><strong>(i)</strong> named in <a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Schedule 1</a> of this Agreement; or</p><p><strong>(ii)</strong> named in Appendix 1 of the Nurses and Midwives (Victorian Public Sector) (Single Interest Employers) Enterprise Agreement 2020 – 2024</p><p><strong>(iii)</strong> that was registered and subsidised pursuant to the Hospital and Charities Act 1958 or the Health Services Act 1988; or</p><p><strong>(iv)</strong> the Cancer Institute constituted under the Cancer Act 1958; or</p><p><strong>(v)</strong> the Fairfield Hospital Board; or</p><p><strong>(vi)</strong> the Victorian Bush Nursing Association (Inc.); or</p><p><strong>(vii)</strong> a Bush Nursing institution; or</p><p><strong>(viii)</strong> the Victorian Institute of Forensic Mental Health</p><p><strong>(f)</strong> LSL Act means the Long Service Leave Act 2018 (Vic).</p><p><strong>(g)</strong> Month means a calendar month.</p><p><strong>(h)</strong> Pay means</p><p><strong>(i)</strong> For a full-time Employee, remuneration for an Employee’s normal weekly hours of work calculated at the employee’s ordinary time rate of</p><p>pay provided in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> at the time the leave is taken or (if the Employee dies before the completion of leave so taken) as at the time of the Employee&#39;s death, and will include the amount of any increase to the Employee’s ordinary time rate of pay which occurred during the period of leave, and</p><p><strong>(ii)</strong> for a part-time Employee whose ordinary hours of work fluctuate because the Employee works additional ordinary shifts (but excluding a permanent variation), the greater of <strong>(A)</strong> the Employee&#39;s ordinary weekly hours at the time long service leave is taken; or <strong>(B)</strong> the average weekly ordinary hours the Employee worked over the preceding 12 months; and</p><p><strong>(iii)</strong> For a casual Employee, the remuneration for the Employees normal weekly hours of work at their ordinary pay is calculated in accordance with sections 15 and 16 of the LSL Act.</p><p><strong>(i)</strong> Service means employment by an Employer, Institution or Statutory Body.</p><p><strong>(j)</strong> Statutory Body means the Hospital and Charities Commission of Victoria, a public entity within the meaning of the Public Administration Act 2004 (Vic), the Department of Education and Early Childhood Development, the Health Commission of Victoria, the Department and the NMBA (and predecessors etc) (however named).</p><p><strong>(k)</strong> Transfer of business occurs in the circumstances described at s.311 of the Act. Part 2 - Long service leave for Group A and Group B Employees</p><p><strong>47.3</strong> Application of Part 2 This part (clauses 47.3 - 47.10) applies to Group A Employees and Group B Employees only.</p><p><strong>47.4</strong> Entitlement</p><p><strong>(a)</strong> Subject to clause 47.6, Employees are entitled to:</p><p><strong>(i)</strong> six months&#39; long service leave on completion of fifteen years of Continuous Service; and</p><p><strong>(ii)</strong> thereafter an additional two months&#39; long service leave on completion of each additional five years of Continuous Service.</p><p><strong>(b)</strong> Subject to subclause 47.6(c)[47.6(c)], an entitlement under subclause 47.4(a)(i)[47.4(a)(i)] may be taken in advance on a pro rata basis if the Employee has accrued at least 7 years&#39; Continuous Service.</p><p><strong>47.5</strong> Calculating Continuous Service</p><p><strong>(a)</strong> Definitions:</p><p><strong>(i)</strong> Continuous Service means continuous service with the same Employer plus any prior service of six months or more with one or more Institutions or Statutory Bodies.</p><p><strong>(ii)</strong> Continuous Casual Employment means, for the purpose of clause 47.5(b), a period or periods of casual Service that are taken to be continuous, because one of the following applies: <strong>(A)</strong> the period starting at the end of a particular instance of employment and ending at the start of another particular instance of employment did not exceed the either allowable period of absence, or 12 weeks (whichever is greater); or</p><p><strong>(B)</strong> the Employee had been employed by an Employer on a regular and systematic basis and the Employee had a reasonable expectation of being re-engaged by the same Employer; or <strong>(C)</strong> the gap between engagements was due to the terms of engagement of the casual Employee; or <strong>(D)</strong> the gap between engagements was caused by seasonal factors; or <strong>(E)</strong> the Employee and Employer agreed, before the start of an absence, to treat the employment as continuous despite the absence.</p><p><strong>(b)</strong> Periods that count towards Continuous Service Service or prior Service during the following periods will be deemed to be continuous and will count as Continuous Service for the purpose of subclause (a):</p><p><strong>(i)</strong> an absence from work on any form of paid leave (e.g. annual leave, personal leave, long service leave and paid parental leave);</p><p><strong>(ii)</strong> any interruption or ending of employment by the Employer if made with the intention of avoiding obligations in respect of long service leave or annual leave</p><p><strong>(iii)</strong> any absence on account of illness or injury arising out of or in the course of the employment for a period during which an Employee is receiving compensation make-up pay under <a href="/eba/ebas/mental-health/common-terms/wages/30-compensation-make-up-pay.html">clause 30</a> (Compensation Make-Up Pay);</p><p><strong>(iv)</strong> any absence from employment on defence service in accordance with section 8 of the Defence Reserve Service (Protection) Act 2001 (Cth);</p><p><strong>(v)</strong> a period of absence on community service leave under the Act;</p><p><strong>(vi)</strong> in the case of unpaid absences not otherwise referenced in this subclause: <strong>(A)</strong> any unpaid leave that is authorised in advance in writing by the Employer to count as service; or <strong>(B)</strong> any unpaid parental leave taken between 1 November 2018 and 30 June 2020 that counts as service because of an application by the Employee under clause 47.11 of the 2020 Agreement; or <strong>(C)</strong> up to (and including) 30 June 2020, any unpaid absence from work of not more than fourteen days in any year on account of illness or injury; or <strong>(D)</strong> on and from 1 July 2020: 1) any period of unpaid leave taken on account of illness or injury 2) a period of Parental Leave, including Parental Leave that is extended under <a href="/eba/ebas/mental-health/common-terms/leave/50-parental-leave.html">clause 50.12</a>; and 3) the first 52 weeks of any other type of unpaid leave not specifically referenced in this subclause 47.5(b)(iv)</p><p><strong>(vii)</strong> in the case of a casual Employee, a period of Continuous Casual Employment, noting that there will be portability of such service between any Employer, Statutory Body and Institution in accordance with clauses 47.7(c) and 47.22; and</p><p><strong>(viii)</strong> prior Continuous Casual Employment as a Group C Employee that was either: <strong>(A)</strong> with the current Employer; or</p><p><strong>(B)</strong> with one or more Institutions or Statutory Bodies directly associated with such Institutions, provided that the Employee was an Award- entitled Employee at the time their employment with the other Institution or associated Statutory Body was terminated, save that if long service leave was already taken or paid in lieu in respect of any such period, no further benefit to long service leave will arise in respect of that period.</p><p><strong>(ix)</strong> Prior employment with a public health service in another State or Territory or Council in Victoria as defined in the Local Government Act 2020, as follows: <strong>(A)</strong> Such employment may only be recognised on the first occasion that the Employee commences employment with an Employer after 20 May 2025 <strong>(B)</strong> Such employment will only be recognised in respect of the period of employment that was recognised as continuous service for the purpose of the Employee&#39;s long service leave entitlement with the public health service or Council (as applicable); and <strong>(C)</strong> Such employment will only be recognised where the break between ceasing employment with the interstate public health service, and commencing employment with the Employer, is no more than the greater of two Months or the Allowable Period of Absence. Save that if long service leave was already taken or paid in lieu in respect of any such period, no further benefit to long service leave will arise in respect of that period.</p><p><strong>(c)</strong> Periods that do not break Continuous Service, but do not count towards Continuous Service Unless otherwise agreed in writing in advance between the Employer and Employee, the following periods do not break Continuous Service but do not count towards an employee&#39;s Continuous Service for the purpose of calculating the employee&#39;s long service leave entitlement:</p><p><strong>(i)</strong> any authorised period of unpaid leave not referred to in sub-clause 47.5(b);</p><p><strong>(ii)</strong> subject to the requirements of the FW Act, any interruption arising directly or indirectly from an industrial dispute</p><p><strong>(iii)</strong> any period between the engagement with one Institution or Statutory Body and another provided it is less than the allowable period of absence from employment</p><p><strong>(iv)</strong> the dismissal of an employee if the employee is re-employed by the same Employer within a period not exceeding two months from the date of such dismissal</p><p><strong>(v)</strong> any absence on account of injury arising out of or in the course of their employment not covered by a period in which A Group A Employee or Group B Employee is receiving accident make up pay or other paid leave</p><p><strong>(vi)</strong> any unpaid absence of not more than 24 months for the sole purpose of undertaking a course of study related to nursing or midwifery where the written approval of the Employer is given; and</p><p><strong>(vii)</strong> any absence from work of an Employee for a period not exceeding twelve months in respect of any pregnancy or adoption not covered by 47.5(b)(i) or 47.5(b)(vi).</p><p><strong>(viii)</strong> The break between periods of employment that is referenced above at subclause 47.5(b)(ix)(C).</p><p><strong>47.6</strong> Taking of leave</p><p><strong>(a)</strong> When leave is to be taken Long service leave will be granted by the Employer within six months from the date of the entitlement arising under clause 47.4(a) save that:</p><p><strong>(i)</strong> long service leave may be postponed to a mutually agreeable date</p><p><strong>(ii)</strong> if agreement cannot be reached, the date will be determined by a member of the Fair Work Commission provided that such a determination will not require leave to commence before six months from the date of such determination; and</p><p><strong>(iii)</strong> leave the subject of approval or grant under clause 47.6(c) shall be taken in accordance with the terms of the application or agreement.</p><p><strong>(b)</strong> How leave is to be taken Long service leave will be taken:</p><p><strong>(i)</strong> in one or more periods, with each period being not less than 1 day; or</p><p><strong>(ii)</strong> where it is taken as part of a transition to retirement arrangement, any other way agreed upon by the Employer and Employee.</p><p><strong>(c)</strong> Long service leave in advance</p><p><strong>(i)</strong> If a Group A Employee or Group B Employee has completed ten years&#39; Continuous Service, an Employer may, by agreement with the Employee, grant long service leave in advance on a pro rata basis.</p><p><strong>(ii)</strong> Supplementary to subclause 47.6(c)(i), if a Group A Employee or Group B Employee requests to take long service leave on a pro rata basis under clause 47.4(b) , the Employer must grant the Employee&#39;s request to take long service leave as soon as practicable after receiving the request unless the Employer has reasonable business grounds for refusing the request.</p><p><strong>(d)</strong> Flexible taking of leave: double leave at half pay</p><p><strong>(i)</strong> An Employer may approve an application by an Employee to take double the period of long service leave at half pay.</p><p><strong>(ii)</strong> Employees should seek independent advice regarding the taxation and superannuation implications of seeking payment under this subclause 47.6(d). The Employer will not be held responsible in any way for the cost or outcome of any such advice.</p><p><strong>(iii)</strong> The Employer, if requested by the Employee, will provide information as to the amount of tax the Employer intends to deduct where payment of long service leave is sought under clause 47.6(d)(i).</p><p><strong>(iv)</strong> If granting the request under this sub-clause would result in an additional cost to the Employer, the Employer may refuse the Employee&#39;s request.</p><p><strong>(v)</strong> Flexible taking of long service leave does not affect an Employee’s period of continuous service recognised. For example, an Employee taking 12 months at half pay will, for the purpose of calculating continuous service, have six (6) months of continuous service recognised. An Employee taking three (3) months at double pay will have 6 months of continuous service recognised. In either case service will not be broken.</p><p><strong>47.7</strong> Payment on termination of employment</p><p><strong>(a)</strong> Interpretation For the purposes of this clause 47.7, termination of employment has its ordinary meaning, provided that:</p><p><strong>(i)</strong> it is taken to occur upon conversion from full-time or part-time employment to casual employment; and</p><p><strong>(ii)</strong> it is not taken to occur at the cessation of each shift as a casual Employee.</p><p><strong>(b)</strong> Basic entitlement at termination of employment Except where an election is made under clause 47.7(c) below, an Employee is entitled to payment in lieu of untaken long service leave upon termination of employment (equal to one thirtieth of the period of Continuous Service less any long service leave taken), as follows:</p><p><strong>(i)</strong> For Group A Employees: <strong>(A)</strong> if, as at the termination date, the Employee&#39;s period of Continuous Service is not less than four years, and the termination occurred for any reason other than the Employee&#39;s behaviour; or <strong>(B)</strong> if the Employee would have otherwise been entitled to take long service leave under clause 47.4.</p><p><strong>(ii)</strong> For Group B Employees if, as at the termination date, the Employee would have been entitled to take long service leave under clause 47.4.</p><p><strong>(c)</strong> Election for payment of entitlement or transfer of entitlement at termination</p><p><strong>(i)</strong> An Employee who has an entitlement to take long service leave on a pro rata basis under clause 47.4(b) (who therefore has less than 15 years continuous service) and who intends to be re-employed by another Institution or Statutory Body may: <strong>(A)</strong> request in writing that payment for accrued long service leave be deferred until after the Employee’s allowable period of absence (as defined above) has expired; and <strong>(B)</strong> where the Employee notifies the initial Employer in writing within the allowable period of absence that the Employee has been employed by such an employer, and the re-employment meets the criteria set out in in subclause 47.7(c)(iii) below, the initial Employer is no longer required to make payment to the Employee in respect of such service.</p><p><strong>(ii)</strong> Where the notice referred to at 47.7(c)(i)(B) is not provided prior to or within the allowable period of absence the Employer will, upon the expiration of the allowable period of absence, make payment in lieu of long service leave as per subclause 47.7(b).</p><p><strong>(iii)</strong> For the purposes of this subclause, re-employment by another Institution or Statutory Body means employment as a Group A Employee or Group B Employee.</p><p><strong>(iv)</strong> For the removal of doubt, an Employee may not make an election under this subclause (c) unless: <strong>(A)</strong> the Employee has an entitlement to take long service leave under clause 47.4(a); and <strong>(B)</strong> if the receiving employer is not covered by this Agreement, that receiving employer has agreed to the transfer.</p><p><strong>(d)</strong> Payment in lieu of long service leave on the death of an Employee Where an Employee dies while still in the employ of the Employer, payment in lieu of long service leave will be made to the Employee’s personal representative in accordance with clause 47.7(b) above.</p><p><strong>47.8</strong> Public holidays and Accrued Days Off See also <a href="/eba/ebas/mental-health/rpn-pen-mho/leave/98-public-holidays.html">clauses 98</a>, 135, 179 and 213 (Public Holidays) and 162 and 197 (Accrued Days Off). Long service leave is inclusive of any public holiday or ADO occurring during the period when leave is taken.</p><p><strong>47.9</strong> Proof of sufficient aggregate of service The onus of proving a sufficient aggregate of service to support a claim for any long service leave entitlement will at all times rest upon the Employee concerned. A Certificate of Service in accordance with <a href="/eba/ebas/mental-health/schedules/09-certificate-of-service.html">Schedule 9</a> will constitute acceptable proof.</p><p><strong>47.10</strong> No entitlement arising for periods of leave already taken For the removal of doubt, where an Employee makes an election under clause 47.7(c) such that their previous service is recognised by the new Employer, the Employee’s previous employer is no longer liable to make any payment in lieu of that employee’s service. Part 3 - Long service leave for Group C Employees</p><p><strong>47.11</strong> Application of Part 3 A Group C Employee shall be entitled to long service leave with ordinary pay in accordance with this Part 3 (clauses 47.11 - 47.18).</p><p><strong>47.12</strong> Interpretation For the purposes of this Part 3:</p><p><strong>(a)</strong> One Employer has the meaning given in section 11 of the LSL Act</p><p><strong>(b)</strong> Continuous employment has the meaning given in section 12 of the LSL Act</p><p><strong>(c)</strong> Ordinary pay has the meanings given in sections 15, 17 and 21 of the LSL Act and</p><p><strong>(d)</strong> Normal weekly hours has the meaning given in sections 16 and 17 of the LSL Act.</p><p><strong>47.13</strong> Entitlement At any time after completing 7 years of continuous employment with one Employer, an Employee is entitled to an amount of long service leave on ordinary pay equal to 1/60th of the Employee&#39;s total period of continuous employment less any period of long service leave taken during that period.</p><p><strong>47.14</strong> Taking of leave</p><p><strong>(a)</strong> When leave is to be taken In accordance with s.18(2) of the LSL Act, an Employer must grant an Employee&#39;s request to take long service leave as soon as practicable after receiving the request unless the Employer has reasonable business grounds for refusing the request.</p><p><strong>(b)</strong> How leave is to be taken In accordance with s.18(1) of the LSL Act, an Employee may request to take long service leave for a period of not less than 1 day.</p><p><strong>(c)</strong> Long service leave in advance</p><p><strong>(i)</strong> Subject otherwise to this Part 3 and in accordance with s.8(1) of the LSL Act, an Employer may agree to an Employee taking long service leave prior to them completing 7 years of continuous employment and at any time before they become entitled to long service leave.</p><p><strong>(ii)</strong> If an Employee takes long service leave in advance and the Employee&#39;s employment ends before the entitlement to the leave would otherwise have accrued: <strong>(A)</strong> the amount paid for the proportion of leave which the Employee will not become entitled becomes an amount owed by the Employee to the Employer; <strong>(B)</strong> the Employer may deduct this amount from any payment owed to the Employee as a result of the ending of employment; and <strong>(C)</strong> the relevant period of service will not count as a period in respect of which long service leave has already been taken (or paid in lieu) for the purpose of clause 47.5(b) above (Periods that count towards Continuous Service for Group A and Group B Employees).</p><p><strong>(d)</strong> Flexible taking of leave: double leave at half pay</p><p><strong>(i)</strong> An employee may request an Employee to take double the period of long service leave at half pay.</p><p><strong>(ii)</strong> An Employer must grant such a request unless: <strong>(A)</strong> granting the request would result in an additional cost to the Employer; or <strong>(B)</strong> the Employer otherwise has reasonable business grounds for refusing the request.</p><p><strong>(iii)</strong> Employees should seek independent advice regarding the taxation and superannuation implications of seeking payment under this subclause 47.14(d). The Employer will not be held responsible in any way for the cost or outcome of any such advice.</p><p><strong>(iv)</strong> The Employer, if requested by the Employee, will provide information as to the amount of tax the Employer intends to deduct where payment of long service leave is sought under this subclause.</p><p><strong>47.15</strong> Payment on termination of employment</p><p><strong>(a)</strong> Basic entitlement at termination of employment An Employee with seven or more years of continuous employment is entitled to payment in lieu of untaken long service leave upon termination of employment, calculated at 1/60th of the period of continuous employment.</p><p><strong>(b)</strong> Payment in lieu of long service leave on the death of an Employee Where an Employee has completed at least seven years’ continuous employment and dies while still in the employ of the Employer, payment in lieu of long service leave will be made to the Employee’s personal representative equal to that in clause 47.15(a) above.</p><p><strong>47.16</strong> Public holidays &amp; Annual leave Long service leave does not include any public holiday occurring, or annual leave taken, during the period when the long service leave is taken.</p><p><strong>47.17</strong> No entitlement arising for periods of leave already taken For the removal of doubt, no entitlement to long service leave (or payment in lieu) arises in respect of continuous employment for which long service leave has already been taken or payment in lieu of leave has been received.</p><p><strong>47.18</strong> Other terms and conditions necessary for this Part Any other term or condition necessary for the operation of this Part shall be in accordance with the applicable term or condition in the LSL Act. Part 4 - Common conditions applicable to all Employees</p><p><strong>47.19</strong> Payment for period of leave</p><p><strong>(a)</strong> Payment will be made in one of the following ways:</p><p><strong>(i)</strong> in full advance when the Employee commences their leave</p><p><strong>(ii)</strong> at the same time as payment would have been made if the Employee had remained on duty; or</p><p><strong>(iii)</strong> in any other way agreed between the Employer and the Employee.</p><p><strong>(b)</strong> Where an Employee has been paid in advance, and an increase occurs in the ordinary time rate of pay during the period of long service leave taken, the Employee will be entitled to receive payment of the amount of any increase in pay at the completion of such leave.</p><p><strong>47.20</strong> Records The Employer will keep a long service leave record for each Employee, containing particulars of service, leave taken and payments made.</p><p><strong>47.21</strong> Transfer of business Where a Transfer of Business occurs, an Employee who worked with the old Employer and who continues in the service of the new Employer will be entitled to count their service with the old Employer as service with the new Employer for the purposes of this clause.</p><p><strong>47.22</strong> Concurrent Service</p><p><strong>(a)</strong> Subject to subclause (b), concurrent service with two or more Employers remains separate and distinct.</p><p><strong>(b)</strong> If a full-time or part-time Group A or Group B Employee transfers from an Employer (the first Employer) to another employer (the new employer) into an equivalent full-time or part-time role, but retains concurrent employment with the first Employer as a casual Employee, then:</p><p><strong>(i)</strong> if <strong>(A)</strong> the new employer is an Employer or another Institution or Statutory Body; and <strong>(B)</strong> the new employer has agreed (or is required) to recognise the Employee&#39;s service with the first Employer for long service leave purposes; and <strong>(C)</strong> the Employee notifies the first Employer of the transfer in accordance with sub-clause 47.7(c) (Election for payment of entitlement or transfer of entitlement at termination), the first Employer will no longer be liable for the service, and the long service leave liability for the service will transfer to the new Employer.</p><p><strong>(ii)</strong> Any casual service that occurs with the first Employer after the transfer referred to in (i) above will be considered separate and distinct service on and from the date on which the employee commenced employment with the new Employer, provided that: <strong>(A)</strong> the qualifying period required to accrue an entitlement to long service leave with the first Employer does not reset (that is, the Employee&#39;s prior service with the first Employer can be counted</p><p>when calculating any future entitlement to long service leave with the first Employer); <strong>(B)</strong> no benefit to long service leave will arise with the first Employer in respect of the prior period of employment with the first Employer; and <strong>(C)</strong> the Employee&#39;s prior service with the first Employer is to be disregarded when calculating the Employee&#39;s normal weekly hours with the first Employer (e.g. for the purpose of sections 16 and 17 of the LSL Act).</p><p><strong>(iii)</strong> If the employee is not entitled to transfer their service from the first Employer to the new Employer, or does not take the steps required in sub-clause 47.7(c) within the allowable period of absence, the first Employer will make payment in lieu of long service leave for the Continuous Service with the first Employer upon ceasing permanent employment with the first Employer (under clause 47.7(b) - Basic entitlement at termination of employment): Example 1: A Group B Employee is employed at the same time by Employer A, and Employer B. The Group B Employee accrues service towards long service leave at each of Employer A and Employer B. If the Employee had been employed by Employer A for 11 years and Employer B for 6 years, the Employee can take LSL from Employer A, but would need to continue working at Employer B until sufficient Continuous Service had accrued. If the Employee resigned from both Employer A and Employer B, and went to work for Employer C, the Employee could:</p><p><strong>(a)</strong> transfer the 6 years&#39; service with Employer B to Employer C; and</p><p><strong>(b)</strong> have the accrued LSL from the 11 years&#39; service with Employer A paid out in lieu on termination. Example 2: A Group A Employee has worked for Employer A for 6 years. The Employee commences employment with Employer B as a full-time Employee. To take up this opportunity, the Employee ceases permanent employment with Employer A. However, the Employee commences a casual employment relationship with Employer A within 12 weeks after resigning from their permanent position with Employer A. The Employee:</p><p><strong>(a)</strong> will be paid in lieu of 6 years&#39; service with Employer A (in accordance with clause 47.7(b)(i)(A)) unless a valid election is made to transfer the 6 years&#39; service with Employer A to Employer B. If a valid election is made, the Employee would be eligible to take LSL with Employer B once sufficient Continuous Service had accrued (taking into account the transferred service); and</p><p><strong>(b)</strong> could take LSL on a pro rata basis with Employer A after sufficient Continuous Service had accrued, save that if a valid election was made to transfer the Employee&#39;s initial service to Employer B, no entitlement would arise in respect of that period with Employer A.</p><p><strong>47.23</strong> Savings</p><p><strong>(a)</strong> Clause 47.22(b) shall not apply to an Employee classified as a Health Information Manager, Play Therapist, or an Employee of Royal Melbourne Hospital classified under <a href="/eba/ebas/mental-health/schedules/06-support-services-employee-classifications.html">Schedule 6</a>, unless the Industrial Division of the Magistrates Court provides an opinion that determines generally the rights of applicable Employees under this Agreement under sub-section 23(2) of the LSL Act that the long service leave entitlements provided by this Agreement are more favourable to the relevant employees than those provided by the LSL Act.</p><p><strong>(b)</strong> The Unions and VHIA must make an application to the Magistrates Court under section 24 of the LSL Act for an opinion referred to in section 4.6(a) as soon as reasonably practicable after the Agreement has been approved by the Fair Work Commission.</p><p><strong>(c)</strong> No Employee shall otherwise suffer any detriment as a result of the operation of this clause to their entitlement to long service leave existing immediately prior to the coming into force of this clause</p><p>Plain language terms: LSL, long service, LSL entitlement.</p>',152)])])}const u=o(a,[["render",s]]);export{g as __pageData,u as default};
